function Tag({ children, light, noBg }) {
  return (
    <span
      style={{
        display: "inline-block",
        background: noBg
          ? "transparent"
          : light
            ? "rgba(232,51,74,0.18)"
            : "#fdeaed",
        color: light ? "#ff8090" : "#e8334a",
        borderRadius: 20,
        padding: "5px 14px",
        fontSize: 11,
        fontWeight: 700,
        letterSpacing: "1.5px",
        textTransform: "uppercase",
        fontFamily: "'Inter', sans-serif",
        marginBottom: 14,
      }}
    >
      {children}
    </span>
  );
}

